{
  "schema_version": 1,
  "request_id": "rf-suggest-ghost-chain-feed-heater-flash-alternate-candidate-tab-after-other-skip-001",
  "project": "radishflow",
  "task": "suggest_ghost_completion",
  "answers": [
    {
      "summary": "当前给出 ghost 建议：将 Heater-6 的 outlet 连接到 Flash Drum 605B 的 inlet。",
      "issues": [],
      "proposed_actions": [
        {
          "action": "ghost_completion",
          "ghost_completion": {
            "title": "连接 Heater-6 出口到 Flash Drum 605B 入口",
            "target": {
              "unit_id": "heater-6",
              "port_key": "outlet",
              "target_node_id": "flash-26.inlet"
            },
            "rationale": "用户已连接 Feed 605 到 Heater-6，且 Heater-6 的 outlet 未连接。附近节点中 Flash Drum 605B 的 inlet 距离最近（58px），对齐度最高（0.97），拓扑模式为 feed_heater_flash_chain，且该候选被标记为高置信度和 Tab 默认。用户之前跳过了连接到 Flash Drum 605A 的候选，因此推荐连接到 Flash Drum 605B。",
            "patch": {
              "operations": [
                {
                  "op": "add",
                  "path": "/streams/-",
                  "value": {
                    "id": "H-605",
                    "name": "H-605",
                    "source_unit_id": "heater-6",
                    "source_port": "outlet",
                    "target_unit_id": "flash-26",
                    "target_port": "inlet"
                  }
                }
              ]
            },
            "preview": {
              "description": "将添加一条名为 H-605 的流，连接 Heater-6 的 outlet 到 Flash Drum 605B 的 inlet。",
              "accept_key": "Tab",
              "manual_only": false
            },
            "apply": {
              "command_kind": "accept_ghost_completion",
              "candidate_ref": "cand-heater-6-outlet-flash-26"
            },
            "risk_level": "low",
            "requires_confirmation": false
          }
        }
      ]
    }
  ]
}
